// Calculate category counts
categories.forEach(cat => {
  cat.count = books.filter(b => b.category === cat.id).length;
});

// Weekly featured books (simulate based on current week)
const weeklyBookIds = [39, 32, 20, 25, 23, 30, 21, 27, 35]; // Danh sách sách trong tuần
const weeklyBooks = weeklyBookIds.map(id => books.find(b => b.id === id));

// State
let readBooks = JSON.parse(localStorage.getItem('readBooks') || '[]');
let currentPage = 'home';
let searchQuery = '';

// ============== NAVIGATION ==============
function navigateTo(page, data) {
  currentPage = page;
  const main = document.getElementById('mainContent');
  
  // Update nav links
  document.querySelectorAll('.nav-link').forEach(link => {
    link.classList.remove('active');
    if (link.dataset.page === page) link.classList.add('active');
  });

  switch(page) {
    case 'home': renderHome(); break;
    case 'categories': renderCategories(); break;
    case 'category': renderCategoryPage(data); break;
    case 'weekly': renderWeekly(); break;
    case 'mybooks': renderMyBooks(); break;
    case 'search': renderSearch(data); break;
    default: renderHome();
  }

  window.scrollTo({ top: 0, behavior: 'smooth' });
}

