// ============== BOOK CARD ==============
function renderBookCard(book, isReadPage = false) {
  const isRead = readBooks.includes(book.id);
  const cat = categories.find(c => c.id === book.category);
  
  return `
    <div class="book-card bg-white rounded-2xl overflow-hidden border border-gray-100 cursor-pointer group" onclick="openBookModal(${book.id})">
      <div class="relative overflow-hidden aspect-[3/4]">
        <img src="${book.cover}" alt="${book.title}" class="book-cover w-full h-full object-cover">
        <div class="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <div class="absolute bottom-4 left-4 right-4">
            <button onclick="event.stopPropagation(); toggleReadBook(${book.id})" class="w-full px-4 py-2 ${isRead ? 'bg-green-500' : 'bg-white/90'} ${isRead ? 'text-white' : 'text-gray-800'} text-sm font-medium rounded-xl hover:scale-105 transition-all backdrop-blur-sm">
              ${isRead ? '✓ Đã đọc' : 'Đánh dấu đã đọc'}
            </button>
          </div>
        </div>
        ${isRead ? `
          <div class="absolute top-3 right-3">
            <div class="read-badge px-2 py-1 text-white text-xs font-bold rounded-lg flex items-center gap-1">
              <i data-lucide="check" class="w-3 h-3"></i> Đã đọc
            </div>
          </div>
        ` : ''}
        <div class="absolute top-3 left-3">
          <div class="px-2 py-1 bg-black/50 text-white text-xs font-medium rounded-lg backdrop-blur-sm">
            ${cat?.name || ''}
          </div>
        </div>
      </div>
      <div class="p-4">
        <h3 class="font-semibold text-sm mb-1 line-clamp-1 group-hover:text-primary-600 transition-colors">${book.title}</h3>
        <p class="text-xs text-gray-400 mb-2">${book.author}</p>
        <div class="flex items-center justify-between">
          <div class="flex items-center gap-1">
            <i data-lucide="star" class="w-3.5 h-3.5 text-warm-400 fill-warm-400"></i>
            <span class="text-xs font-medium">${book.rating}</span>
          </div>
          <span class="text-xs text-gray-400">${book.pages} trang</span>
        </div>
      </div>
    </div>
  `;
}

// ============== BOOK MODAL ==============
function openBookModal(bookId) {
  const book = books.find(b => b.id === bookId);
  if (!book) return;

  const cat = categories.find(c => c.id === book.category);
  const isRead = readBooks.includes(book.id);
  const relatedBooks = books.filter(b => b.category === book.category && b.id !== book.id).slice(0, 3);

  const modal = document.getElementById('bookModal');
  const content = document.getElementById('bookModalContent');

  content.innerHTML = `
    <div class="sticky top-0 z-10 bg-white/90 backdrop-blur-xl border-b border-gray-100 px-6 py-4 flex items-center justify-between">
      <h2 class="font-semibold text-sm text-gray-500">Chi tiết sách</h2>
      <button onclick="closeBookModal()" class="w-10 h-10 rounded-xl bg-gray-100 hover:bg-gray-200 flex items-center justify-center transition-colors">
        <i data-lucide="x" class="w-5 h-5"></i>
      </button>
    </div>
    
    <div class="p-6 md:p-8">
      <!-- Header -->
      <div class="flex flex-col sm:flex-row gap-6 mb-8">
        <div class="flex-shrink-0 mx-auto sm:mx-0">
          <div class="relative">
            <img src="${book.cover}" alt="${book.title}" class="w-44 h-60 object-cover rounded-2xl shadow-xl book-spine">
            ${isRead ? `
              <div class="absolute -top-2 -right-2 read-badge px-3 py-1 text-white text-xs font-bold rounded-full flex items-center gap-1 shadow-lg">
                <i data-lucide="check" class="w-3 h-3"></i> Đã đọc
              </div>
            ` : ''}
          </div>
        </div>
        <div class="flex-1 text-center sm:text-left">
          <span class="inline-block px-3 py-1 bg-gradient-to-r ${cat?.color || 'from-gray-400 to-gray-600'} text-white text-xs font-semibold rounded-full mb-3">${cat?.name || ''}</span>
          <h1 class="font-display text-2xl md:text-3xl font-bold mb-2">${book.title}</h1>
          <p class="text-gray-500 mb-3">${book.author}</p>
          <div class="flex items-center gap-3 justify-center sm:justify-start mb-4">
            <div class="flex items-center gap-1">
              ${renderStars(book.rating)}
            </div>
            <span class="font-semibold">${book.rating}</span>
            <span class="text-gray-300">|</span>
            <span class="text-gray-400 text-sm">${book.pages} trang</span>
          </div>
          <div class="flex flex-wrap gap-2 justify-center sm:justify-start text-xs text-gray-400 mb-5">
            <span class="px-3 py-1 bg-gray-100 rounded-full">📅 ${book.year}</span>
            <span class="px-3 py-1 bg-gray-100 rounded-full">🌐 ${book.language}</span>
          </div>
          <div class="flex flex-wrap gap-3 justify-center sm:justify-start">
            <button onclick="toggleReadBook(${book.id})" id="readBtnModal" class="px-6 py-2.5 font-medium rounded-xl transition-all hover:scale-105 ${isRead ? 'bg-green-100 text-green-700 border-2 border-green-300' : 'bg-primary-600 text-white hover:bg-primary-700'}">
              ${isRead ? '✓ Đã đọc' : 'Đánh dấu đã đọc'}
            </button>
            <button onclick="shareBook(${book.id})" class="px-6 py-2.5 bg-gray-100 text-gray-600 font-medium rounded-xl hover:bg-gray-200 transition-all hover:scale-105">
              Chia sẻ
            </button>
          </div>
        </div>
      </div>

      <!-- Description -->
      <div class="mb-8">
        <h3 class="font-display text-lg font-bold mb-3 flex items-center gap-2">
          <i data-lucide="align-left" class="w-5 h-5 text-primary-500"></i> Giới thiệu
        </h3>
        <p class="text-gray-600 leading-relaxed">${book.description}</p>
      </div>

      <!-- Quotes -->
      ${book.quotes && book.quotes.length > 0 ? `
        <div class="mb-8">
          <h3 class="font-display text-lg font-bold mb-3 flex items-center gap-2">
            <i data-lucide="quote" class="w-5 h-5 text-primary-500"></i> Trích dẫn hay
          </h3>
          <div class="space-y-3">
            ${book.quotes.map(q => `
              <div class="bg-gradient-to-r from-primary-50 to-purple-50 rounded-xl p-4 border-l-4 border-primary-400">
                <p class="text-gray-700 text-sm italic">${q}</p>
              </div>
            `).join('')}
          </div>
        </div>
      ` : ''}

      <!-- YouTube Video -->
      ${book.youtubeId ? `
        <div class="mb-8">
          <h3 class="font-display text-lg font-bold mb-3 flex items-center gap-2">
            <i data-lucide="play-circle" class="w-5 h-5 text-primary-500"></i> Video Review
          </h3>
          <div class="video-container shadow-lg">
            <iframe src="https://www.youtube.com/embed/${book.youtubeId}" 
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
              allowfullscreen
              loading="lazy"
              title="Video review ${book.title}">
            </iframe>
          </div>
        </div>
      ` : ''}

      <!-- Related Books -->
      ${relatedBooks.length > 0 ? `
        <div class="mb-8">
          <h3 class="font-display text-lg font-bold mb-3 flex items-center gap-2">
            <i data-lucide="library" class="w-5 h-5 text-primary-500"></i> Sách tương tự
          </h3>
          <div class="grid grid-cols-3 gap-3">
            ${relatedBooks.map(rb => `
              <div onclick="openBookModal(${rb.id})" class="cursor-pointer bg-gray-50 rounded-xl p-3 hover:bg-primary-50 transition-colors group">
                <img src="${rb.cover}" alt="${rb.title}" class="w-full aspect-[3/4] object-cover rounded-lg mb-2">
                <h4 class="text-xs font-semibold line-clamp-1 group-hover:text-primary-600">${rb.title}</h4>
                <p class="text-xs text-gray-400">${rb.author}</p>
              </div>
            `).join('')}
          </div>
        </div>
      ` : ''}
    </div>
  `;

  modal.classList.remove('hidden');
  document.body.style.overflow = 'hidden';
  lucide.createIcons();
}

function closeBookModal() {
  const modal = document.getElementById('bookModal');
  modal.classList.add('hidden');
  document.body.style.overflow = '';
}

// ============== UTILITIES ==============
function renderStars(rating) {
  const full = Math.floor(rating);
  const half = rating % 1 >= 0.5;
  let stars = '';
  for (let i = 0; i < 5; i++) {
    if (i < full) {
      stars += '<i data-lucide="star" class="w-4 h-4 star-filled fill-current"></i>';
    } else if (i === full && half) {
      stars += '<i data-lucide="star-half" class="w-4 h-4 star-filled fill-current"></i>';
    } else {
      stars += '<i data-lucide="star" class="w-4 h-4 text-gray-200"></i>';
    }
  }
  return stars;
}

function toggleReadBook(bookId) {
  if (readBooks.includes(bookId)) {
    readBooks = readBooks.filter(id => id !== bookId);
    showToast('Đã bỏ đánh dấu sách');
  } else {
    readBooks.push(bookId);
    showToast('Đã đánh dấu đã đọc ✓');
  }
  localStorage.setItem('readBooks', JSON.stringify(readBooks));
  updateReadCount();
  
  // Re-render current page to update UI
  switch(currentPage) {
    case 'home': navigateTo('home'); break;
    case 'categories': navigateTo('categories'); break;
    case 'category': break; // Keep modal open
    case 'weekly': navigateTo('weekly'); break;
    case 'mybooks': navigateTo('mybooks'); break;
  }

  // Update modal if open
  const modal = document.getElementById('bookModal');
  if (!modal.classList.contains('hidden')) {
    openBookModal(bookId);
  }
}

function updateReadCount() {
  const countEl = document.getElementById('readCount');
  if (readBooks.length > 0) {
    countEl.classList.remove('hidden');
    countEl.textContent = readBooks.length;
  } else {
    countEl.classList.add('hidden');
  }
}

function showToast(message) {
  const toast = document.getElementById('toast');
  const msgEl = document.getElementById('toastMessage');
  msgEl.textContent = message;
  toast.classList.remove('hidden');
  lucide.createIcons();
  
  setTimeout(() => {
    toast.classList.add('hidden');
  }, 2500);
}

function shareBook(bookId) {
  const book = books.find(b => b.id === bookId);
  if (navigator.share) {
    navigator.share({
      title: book.title,
      text: `Khám phá cuốn sách "${book.title}" của ${book.author}`,
    });
  } else {
    navigator.clipboard?.writeText(`Khám phá cuốn sách "${book.title}" của ${book.author}`);
    showToast('Đã sao chép liên kết');
  }
}

function handleSearch(query) {
  searchQuery = query;
  if (query.trim().length >= 2) {
    navigateTo('search', query.trim());
  } else if (query.trim().length === 0 && currentPage === 'search') {
    navigateTo('home');
  }
}

function toggleMobileMenu() {
  const menu = document.getElementById('mobileMenu');
  menu.classList.toggle('hidden');
}

// ============== INIT ==============
document.addEventListener('DOMContentLoaded', () => {
  navigateTo('home');
  updateReadCount();
  
  // Close modal on Escape
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeBookModal();
  });

  // Navbar shadow on scroll
  window.addEventListener('scroll', () => {
    const navbar = document.getElementById('navbar');
    if (window.scrollY > 10) {
      navbar.classList.add('shadow-md');
    } else {
      navbar.classList.remove('shadow-md');
    }
  });
});